#include <bits/stdc++.h>
using namespace std;
int n,a,b,c,d,e,f,g,s[35],sss,h,i,j,k,l,m,res;
int main() {
	cin>>n;
	cin>>a>>b>>c>>d>>e>>f>>g;
	s[a]++;
	s[b]++;
	s[c]++;
	s[d]++;
	s[e]++;
	s[f]++;
	s[g]++;
	while(n--) {
		res=0;
		cin>>a>>b>>c>>d>>e>>f>>g;
		if(s[a]>0) {
			res++;
		}
		if(s[b]>0) {
			res++;
		}
		if(s[c]>0) {
			res++;
		}
		if(s[d]>0) {
			res++;
		}
		if(s[e]>0) {
			res++;
		}
		if(s[f]>0) {
			res++;
		}
		if(s[g]>0) {
			res++;
		}
		if(res==7) {
			sss++;
		}
		if(res==6) {
			h++;
		}
		if(res==5) {
			i++;
		}
		if(res==4) {
			j++;
		}
		if(res==3) {
			k++;
		}
		if(res==2) {
			l++;
		}
		if(res==1) {
			m++;
		}
	}
	cout<<sss<<" "<<h<<" "<<i<<" "<<j<<" "<<k<<" "<<l<<" "<<m<<endl;
	return 0;
}
